diff --git a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
index c3f79fe4f901..6b09b3ca1aec 100644
--- a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
@@ -3865,6 +3865,86 @@ Instruction *InstCombinerImpl::visitSwitchInst(SwitchInst &SI) {
                                     SI.findCaseValue(CI)->getCaseSuccessor());
     return nullptr;
   }
+  // Handle switch on ucmp/scmp intrinsic - convert to icmp + branch
+  if (auto *CI = dyn_cast<CmpIntrinsic>(Cond)) {
+    Value *LHS = CI->getLHS();
+    Value *RHS = CI->getRHS();
+    bool IsSigned = CI->isSigned();
+    auto *IntTy = cast<IntegerType>(CI->getType());
+
+    // Collect destination for each possible ucmp/scmp result (-1, 0, 1)
+    // ucmp/scmp returns: -1 (all ones) for LT, 0 for EQ, 1 for GT
+    ConstantInt *LTVal = ConstantInt::getSigned(IntTy, -1);
+    ConstantInt *EQVal = ConstantInt::get(IntTy, 0);
+    ConstantInt *GTVal = ConstantInt::get(IntTy, 1);
+
+    auto GetDest = [&](ConstantInt *Val) -> BasicBlock * {
+      return SI.findCaseValue(Val)->getCaseSuccessor();
+    };
+
+    BasicBlock *LTDest = GetDest(LTVal);
+    BasicBlock *EQDest = GetDest(EQVal);
+    BasicBlock *GTDest = GetDest(GTVal);
+
+    // Check if we have exactly 2 unique destinations
+    SmallPtrSet<BasicBlock *, 4> UniqueDests;
+    UniqueDests.insert(LTDest);
+    UniqueDests.insert(EQDest);
+    UniqueDests.insert(GTDest);
+    if (UniqueDests.size() != 2)
+      return nullptr;
+
+    // Determine the two destinations
+    auto It = UniqueDests.begin();
+    BasicBlock *DestA = *It++;
+    BasicBlock *DestB = *It;
+
+    // Determine which destination gets GT (value 1)
+    bool GTToDestA = (GTDest == DestA);
+
+    // Determine predicate based on the pattern
+    // GT (1) to DestA, LT (-1) and EQ (0) to DestB: ugt/sgt
+    // GT (1) to DestA, LT (-1) to DestB, EQ (0) to DestA: uge/sge
+    // GT (1) to DestA, LT (-1) to DestA, EQ (0) to DestB: ult/slt (NE predicate actually)
+    // GT (1) to DestB, LT (-1) and EQ (0) to DestA: ule/sle
+    // GT (1) to DestB, LT (-1) to DestA, EQ (0) to DestB: ult/slt (inverse)
+    // GT (1) to DestB, LT (-1) to DestB, EQ (0) to DestA: eq
+
+    ICmpInst::Predicate Pred;
+    if (GTToDestA) {
+      if (LTDest == DestB && EQDest == DestB) {
+        // GT to A, LT+EQ to B: GT predicate
+        Pred = IsSigned ? ICmpInst::ICMP_SGT : ICmpInst::ICMP_UGT;
+      } else if (LTDest == DestB && EQDest == DestA) {
+        // GT+EQ to A, LT to B: GE predicate
+        Pred = IsSigned ? ICmpInst::ICMP_SGE : ICmpInst::ICMP_UGE;
+      } else {
+        // GT+LT to A, EQ to B: NE predicate
+        Pred = ICmpInst::ICMP_NE;
+      }
+    } else {  // GTToDestB
+      if (LTDest == DestA && EQDest == DestA) {
+        // GT to B, LT+EQ to A: LE predicate
+        Pred = IsSigned ? ICmpInst::ICMP_SLE : ICmpInst::ICMP_ULE;
+      } else if (LTDest == DestA && EQDest == DestB) {
+        // GT+EQ to B, LT to A: LT predicate
+        Pred = IsSigned ? ICmpInst::ICMP_SLT : ICmpInst::ICMP_ULT;
+      } else {
+        // GT+LT to B, EQ to A: EQ predicate
+        Pred = ICmpInst::ICMP_EQ;
+      }
+    }
+
+    // Create the icmp and branch
+    Builder.SetInsertPoint(&SI);
+    Value *ICmp = Builder.CreateICmp(Pred, LHS, RHS, "icmp");
+    BranchInst *BI = Builder.CreateCondBr(ICmp, GTToDestA ? DestA : DestB,
+                                          GTToDestA ? DestB : DestA);
+
+    // The switch will be deleted by the instcombine framework
+    return nullptr;
+  }
+

   return nullptr;
 }

